mapper.select:
SELECT a.*, e.EMPLOYEE_NAME AS writerName, d.DEPT_NAME AS writerDeptName, (SELECT COUNT(*) FROM ARCHIVE_FILE f WHERE f.ARCHIVE_ID = a.ARCHIVE_ID) AS fileCount FROM ARCHIVE a JOIN EMPLOYEE e ON a.WRITER_ID = e.EMPLOYEE_ID LEFT JOIN DEPARTMENT d ON e.DEPT_ID = d.DEPT_ID WHERE a.REPO_ID = #{repoId}
AND (a.ARCHIVE_TITLE LIKE CONCAT('%', #{keyword}, '%') OR a.ARCHIVE_CONTENT LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY a.ARCHIVE_ID DESC LIMIT #{size} OFFSET #{offset}
